    public static func newComment(_ input: NewComment, baseVersion: Int64? = 0) -> SyncularGeneratedOperation {
        var payload: [String: SyncularJsonValue] = [:]
        payload["task_id"] = .string(input.taskId)
        if let value = input.projectId {
            payload["project_id"] = .string(value)
        }
        payload["body"] = .string(input.body)
        payload["author_id"] = .string(input.authorId)
        payload["deleted"] = .int(input.deleted ?? 0)
        return SyncularGeneratedOperation(
            table: "comments",
